import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const LABELS = {
  true: { text: '진행중', color: '#4caf50' },
  false: { text: '모집완료', color: '#f44336' },
};

function PostDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [post, setPost] = useState(null);
  const [comments, setComments] = useState([]);
  const [commentText, setCommentText] = useState('');
  const [author, setAuthor] = useState('');

  useEffect(() => {
    fetch(`/api/posts/${id}`)
      .then(res => res.json())
      .then(data => setPost(data.post));
    fetch(`/api/comments/post/${id}`)
      .then(res => res.json())
      .then(data => setComments(data.comments || []));
  }, [id]);

  const handleComment = async () => {
    if (!commentText || !author) return;
    await fetch('/api/comments', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ post_id: id, content: commentText, author })
    });
    setCommentText('');
    fetch(`/api/comments/post/${id}`)
      .then(res => res.json())
      .then(data => setComments(data.comments || []));
  };

  if (!post) return <div>로딩중...</div>;

  return (
    <div style={{ maxWidth: 800, margin: '40px auto', background: '#f9f9f9', borderRadius: 16, boxShadow: '0 2px 8px #bbb', padding: 32 }}>
      <div style={{ display: 'flex', alignItems: 'center', marginBottom: 16 }}>
        <span style={{
          display: 'inline-block',
          padding: '2px 12px',
          borderRadius: 14,
          background: LABELS[post.is_recruiting]?.color,
          color: '#fff',
          fontWeight: 600,
          fontSize: 15,
          marginRight: 12
        }}>{LABELS[post.is_recruiting]?.text}</span>
        <h2 style={{ margin: 0 }}>{post.title}</h2>
      </div>
      <div style={{ marginBottom: 12, color: '#666' }}>
        <span>작성자: {post.author}</span> | <span>작성일: {new Date(post.created_at).toLocaleString()}</span>
        {post.updated_at && post.updated_at !== post.created_at && (
          <> | <span>수정일: {new Date(post.updated_at).toLocaleString()}</span></>
        )}
        | <span>조회수: {post.views}</span>
      </div>
      <div style={{ marginBottom: 16 }}>
        {[post.region, post.age_group, post.skill_level]
          .filter(Boolean)
          .map((tag, i) => (
            <span key={i} style={{
              display: 'inline-block',
              background: '#1976d2',
              color: '#fff',
              borderRadius: 8,
              padding: '2px 8px',
              marginRight: 4,
              fontSize: 13,
            }}>{tag}</span>
          ))}
        {post.extra_tags && post.extra_tags.split(',').map((tag, i) => (
          <span key={i} style={{
            display: 'inline-block',
            background: '#607d8b',
            color: '#fff',
            borderRadius: 8,
            padding: '2px 8px',
            marginRight: 4,
            fontSize: 13,
          }}>{tag.trim()}</span>
        ))}
      </div>
      <div style={{ background: '#fff', borderRadius: 12, padding: 24, marginBottom: 24, minHeight: 120, fontSize: 17, boxShadow: '0 1px 4px #eee', borderLeft: '8px solid #4caf50', position: 'relative' }}>
        <img src="https://cdn-icons-png.flaticon.com/512/861/861512.png" alt="축구공" style={{ width: 36, position: 'absolute', right: 16, top: 16, opacity: 0.2 }} />
        <div style={{ whiteSpace: 'pre-line' }}>{post.content}</div>
        <div style={{ marginTop: 16, color: '#444', fontSize: 15 }}>
          <b>모임 시간:</b> {post.meeting_time || '-'}<br />
          <b>장소:</b> {post.meeting_place || '-'}<br />
          <b>모인 인원:</b> {post.member_count || '-'} 명
        </div>
      </div>
      <div style={{ marginBottom: 24 }}>
        <button onClick={() => navigate(-1)} style={{ marginRight: 12 }}>목록으로</button>
        {/* TODO: 작성자일 때만 노출 */}
        <button onClick={() => navigate(`/posts/${id}/edit`)} style={{ marginRight: 8 }}>수정</button>
        <button style={{ color: '#f44336' }}>삭제</button>
      </div>
      <h3>댓글</h3>
      <div style={{ marginBottom: 16 }}>
        <input value={author} onChange={e => setAuthor(e.target.value)} placeholder="작성자" style={{ marginRight: 8 }} />
        <input value={commentText} onChange={e => setCommentText(e.target.value)} placeholder="댓글 내용" style={{ width: 300, marginRight: 8 }} />
        <button onClick={handleComment}>댓글 작성</button>
      </div>
      <CommentTree comments={comments} />
    </div>
  );
}

function CommentTree({ comments }) {
  return (
    <ul style={{ listStyle: 'none', paddingLeft: 0 }}>
      {comments.map(comment => (
        <li key={comment.id} style={{ marginBottom: 12, marginLeft: comment.parent_id ? 32 : 0, background: comment.is_deleted ? '#eee' : '#fafafa', borderRadius: 8, padding: 8 }}>
          <div style={{ color: '#333', fontWeight: 500 }}>
            {comment.is_deleted ? '삭제된 댓글입니다' : comment.author}
            <span style={{ color: '#888', fontWeight: 400, marginLeft: 8, fontSize: 13 }}>
              {new Date(comment.created_at).toLocaleString()}
              {comment.updated_at && comment.updated_at !== comment.created_at && (
                <> (수정됨: {new Date(comment.updated_at).toLocaleString()})</>
              )}
            </span>
          </div>
          {!comment.is_deleted && <div style={{ margin: '4px 0 4px 0' }}>{comment.content}</div>}
          {/* TODO: 수정, 삭제, 답글 버튼 구현 */}
          {comment.children && comment.children.length > 0 && <CommentTree comments={comment.children} />}
        </li>
      ))}
    </ul>
  );
}

export default PostDetail;
